public int sum67(int[] nums)
{
    int sum = 0;
    boolean ifSix = false;
    for (int i = 0; i < nums.length; i++)
    {
        if (ifSix)
        {
            if (nums[i] == 7)
                ifSix = false;
        }
        else if (nums[i] == 6)
        {
            ifSix = true;
        }
        //if ifSix is true, then it goes back into the for loop 
        //and the first if statement becomes true
        else
        {
            sum = sum + nums[i];
        }
        //takes the sum of the numbers when there is no linee of numbers starting
        //with a 6 and ending with a 7
    }
    return sum;
}

private boolean canBalance(int[] nums) {
    int first = 0;
    int second = 0;

    for(int i = 0; i < nums.length; i++)
        second += nums[i];

    for(int i = 0; i <= nums.length - 2; i++) {
        first += nums[i];
        second -= nums[i];

        if(first == second)
            return true;
    }

    return false;
}

